args.sparql:
SELECT ?ship ?shipLabel WHERE {
  ?ship wdt:P1363 ?event.
  ?event wdt:P463 wd:Q59.
  ?event wdt:P276 ?location.
  ?location rdfs:label ?locLabel.
  FILTER(LANG(?locLabel) = 'en')
  FILTER(CONTAINS(LCASE(?locLabel), 'massachusetts'))
  SERVICE wikibase:label { bd:serviceParam wikibase:language "en". }
}

SELECT ?ship ?shipLabel WHERE {
  ?ship p:P1363 ?event.
  ?event ps:P1363 wd:Q145.
  ?event pq:P276 ?location.
  ?location rdfs:label ?locationLabel.
  FILTER(LANG(?locationLabel) = 'en' && CONTAINS(LCASE(?locationLabel), 'massachusetts'))
  SERVICE wikibase:label { bd:serviceParam wikibase:language "en". }
}

SELECT ?ship ?shipLabel WHERE {
  ?ship wdt:P31 wd:Q815913 .  
  ?ship wdt:P599 ?battle .
