  ?ship wdt:P31 wd:Q815913 .  # ship instance
  ?ship wdt:P599 ?battle .     # ship participated in battle
  ?battle wdt:P276 ?location . 
  ?location wdt:P131 wd:Q131 . # location is in Massachusetts
